const steps = ["Travel", "Stay", "Food", "Local", "Plan"];

const ProgressBar = ({ doneCount }) => (
  <div className="progress-row">
    {steps.map((s, i) => (
      <div key={s} className={`prog-step${i < doneCount ? " done" : ""}`}>
        {s}
        <div className="prog-bar">
          <div className="prog-bar-fill" style={{ width: i < doneCount ? "100%" : "0%" }}></div>
        </div>
      </div>
    ))}
  </div>
);

export default ProgressBar;
